import static com.google.gson.stream.JsonScope.NONEMPTY_ARRAY;
import static com.google.gson.stream.JsonScope.NONEMPTY_DOCUMENT;
import static com.google.gson.stream.JsonScope.NONEMPTY_OBJECT;
import java.io.Closeable;
import java.io.Flushable;
import java.math.BigDecimal;
import java.math.BigInteger;
import java.util.Arrays;
import java.util.Objects;
import java.util.concurrent.atomic.AtomicInteger;
import java.util.concurrent.atomic.AtomicLong;
import java.util.regex.Pattern;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;
import java.io.Writer;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class JsonWriter_value_Test {
  private StringWriter stringWriter;
  private JsonWriter jsonWriter;

  @BeforeEach
  void setUp() {
    stringWriter = new StringWriter();
    jsonWriter = new JsonWriter(stringWriter);
  }

  @Test
  void value_null_callsNullValue() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);
    doReturn(spyWriter).when(spyWriter).nullValue();

    JsonWriter returned = spyWriter.value(null);

    verify(spyWriter).nullValue();
    assertSame(spyWriter, returned);
  }

  @Test
  void value_nonNull_executesExpectedFlow() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
    JsonWriter spyWriter = spy(jsonWriter);

    // Stub writeDeferredName and beforeValue to do nothing
    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    // Stub private string(String) method to verify it is called with correct argument
    Method stringMethod = JsonWriter.class.getDeclaredMethod("string", String.class);
    stringMethod.setAccessible(true);

    // We spy the string method call by invoking it through reflection and verify call count later
    // Here we do nothing to the string method, just verify invocation below

    JsonWriter returned = spyWriter.value("testValue");

    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();

    // Verify private string method called once with "testValue"
    // Since string is private, we verify invocation by spying the whole JsonWriter and checking interactions
    // Mockito cannot verify private method calls directly, so we use reflection to invoke it and confirm no exceptions
    // Alternatively, use doCallRealMethod for string method if it were public, but here just check no errors

    assertSame(spyWriter, returned);
  }

  @Test
  void value_emptyString() throws IOException {
    JsonWriter spyWriter = spy(jsonWriter);
    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter returned = spyWriter.value("");

    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
    assertSame(spyWriter, returned);
  }

  @Test
  void value_specialCharactersString() throws IOException {
    String special = "\"\\\b\f\n\r\t\u2028\u2029";
    JsonWriter spyWriter = spy(jsonWriter);
    doNothing().when(spyWriter).writeDeferredName();
    doNothing().when(spyWriter).beforeValue();

    JsonWriter returned = spyWriter.value(special);

    verify(spyWriter).writeDeferredName();
    verify(spyWriter).beforeValue();
    assertSame(spyWriter, returned);
  }
}

